+import React, { useState, useEffect } from 'react';
+import { Activity, FileText, Wrench, Shield, Users, Calendar, LogOut } from 'lucide-react';
+
+const Sidebar = ({ user, activeTab, onTabChange, onLogout }) => {
+  const [restingToday, setRestingToday] = useState([]);
+
+  useEffect(() => {
+    const fetchResting = async () => {
+      try {
+        const token = localStorage.getItem('token');
+        const res = await fetch(`http://${window.location.hostname}:8000/rest-days/today`, {
+          headers: { Authorization: `Bearer ${token}` }
+        });
+        if (res.ok) {
+          const data = await res.json();
+          setRestingToday(data);
+        }
+      } catch (e) {}
+    };
+    fetchResting();
+    const interval = setInterval(fetchResting, 30000);
+    return () => clearInterval(interval);
+  }, []);
+
+  const tabs = [
+    { id: 'run', label: 'Run', icon: <Activity size={18} />, roles: ['ADMIN', 'MASTER', 'NAZORATCHI'] },
+    { id: 'report', label: 'Report', icon: <FileText size={18} />, roles: ['ADMIN', 'MASTER', 'NAZORATCHI'] },
+    { id: 'mechanic', label: 'Mechanic', icon: <Wrench size={18} />, roles: ['ADMIN', 'MASTER', 'NAZORATCHI'] },
+    { id: 'master', label: 'Master', icon: <Users size={18} />, roles: ['ADMIN', 'MASTER'] },
+    { id: 'nazoratchi', label: 'Nazoratchi', icon: <Calendar size={18} />, roles: ['ADMIN', 'NAZORATCHI'] },
+    { id: 'admin', label: 'Settings', icon: <Shield size={18} />, roles: ['ADMIN'] },
+  ];
+
+  const visibleTabs = tabs.filter(t => t.roles.includes(user?.role));
+
+  return (
+    <div className="sidebar">
+      <div style={{ marginBottom: '1.5rem' }}>
+        <h1 style={{ fontSize: '1.4rem', fontWeight: 900, color: 'var(--primary)', margin: 0, letterSpacing: '-1px' }}>
+          SMART ESP32
+        </h1>
+        <p style={{ fontSize: '0.65rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '1px' }}>
+          Industrial Monitor v3.0
+        </p>
+      </div>
+
+      {/* Rest Day Banner */}
+      {restingToday.length > 0 && (
+        <div style={{
+          background: 'rgba(251, 191, 36, 0.1)',
+          border: '1px solid rgba(251, 191, 36, 0.3)',
+          borderRadius: '12px',
+          padding: '0.75rem',
+          marginBottom: '1rem'
+        }}>
+          <div style={{ fontSize: '0.65rem', fontWeight: 700, color: '#fbbf24', textTransform: 'uppercase', marginBottom: '4px' }}>
+            Bugun dam olganlar:
+          </div>
+          <div style={{ fontSize: '0.8rem', color: '#fde68a', fontWeight: 600 }}>
+            {restingToday.map(r => r.operator_name).join(', ')}
+          </div>
+        </div>
+      )}
+
+      {/* Navigation */}
+      <nav style={{ display: 'flex', flexDirection: 'column', gap: '4px', flex: 1 }}>
+        {visibleTabs.map(tab => (
+          <button
+            key={tab.id}
+            onClick={() => onTabChange(tab.id)}
+            style={{
+              display: 'flex',
+              alignItems: 'center',
+              gap: '10px',
+              padding: '10px 14px',
+              borderRadius: '10px',
+              border: 'none',
+              cursor: 'pointer',
+              fontSize: '0.85rem',
+              fontWeight: 600,
+              background: activeTab === tab.id ? 'rgba(0, 210, 255, 0.15)' : 'transparent',
+              color: activeTab === tab.id ? 'var(--primary)' : 'var(--text-muted)',
+              transition: 'all 0.2s',
+              textAlign: 'left',
+            }}
+          >
+            {tab.icon}
+            {tab.label}
+          </button>
+        ))}
+      </nav>
+
+      {/* User Info */}
+      <div style={{ padding: '1rem', background: 'rgba(255,255,255,0.03)', borderRadius: '16px', marginTop: '1rem' }}>
+        <div style={{ marginBottom: '0.75rem' }}>
+          <p style={{ margin: 0, fontSize: '0.9rem', fontWeight: 600 }}>{user?.full_name}</p>
+          <p style={{ margin: 0, fontSize: '0.7rem', color: 'var(--text-muted)' }}>{user?.role}</p>
+        </div>
+        <button
+          onClick={onLogout}
+          style={{
+            width: '100%',
+            padding: '8px',
+            fontSize: '0.8rem',
+            background: '#ef444422',
+            color: '#ef4444',
+            border: '1px solid #ef444444',
+            borderRadius: '8px',
+            cursor: 'pointer',
+            fontWeight: 600,
+            display: 'flex',
+            alignItems: 'center',
+            justifyContent: 'center',
+            gap: '6px'
+          }}
+        >
+          <LogOut size={14} /> Chiqish
+        </button>
+      </div>
+    </div>
+  );
+};
+
+export default Sidebar;

