+import React, { useState, useEffect } from 'react';
+import { Plus, Trash2, Edit2, Save, X } from 'lucide-react';
+
+const AdminPanel = ({ user }) => {
+  const [users, setUsers] = useState([]);
+  const [showForm, setShowForm] = useState(false);
+  const [editId, setEditId] = useState(null);
+  const [form, setForm] = useState({ username: '', password: '', full_name: '', role: 'MASTER' });
+  const [error, setError] = useState('');
+
+  const token = localStorage.getItem('token');
+  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
+  const API = `http://${window.location.hostname}:8000`;
+
+  const fetchUsers = async () => {
+    try {
+      const res = await fetch(`${API}/users`, { headers });
+      if (res.ok) setUsers(await res.json());
+    } catch (e) {}
+  };
+
+  useEffect(() => { fetchUsers(); }, []);
+
+  const resetForm = () => {
+    setForm({ username: '', password: '', full_name: '', role: 'MASTER' });
+    setShowForm(false);
+    setEditId(null);
+    setError('');
+  };
+
+  const handleCreate = async () => {
+    if (!form.username || !form.password || !form.full_name) {
+      setError('Barcha maydonlarni toldiring');
+      return;
+    }
+    try {
+      const res = await fetch(`${API}/users`, {
+        method: 'POST', headers, body: JSON.stringify(form)
+      });
+      if (res.ok) {
+        fetchUsers();
+        resetForm();
+      } else {
+        const data = await res.json();
+        setError(data.detail || 'Xatolik');
+      }
+    } catch (e) { setError('Server xatoligi'); }
+  };
+
+  const handleUpdate = async () => {
+    const body = { full_name: form.full_name, role: form.role };
+    if (form.password) body.password = form.password;
+    try {
+      const res = await fetch(`${API}/users/${editId}`, {
+        method: 'PUT', headers, body: JSON.stringify(body)
+      });
+      if (res.ok) {
+        fetchUsers();
+        resetForm();
+      }
+    } catch (e) { setError('Server xatoligi'); }
+  };
+
+  const handleDelete = async (id) => {
+    if (!confirm('Rostdan ham ochirmoqchimisiz?')) return;
+    try {
+      await fetch(`${API}/users/${id}`, { method: 'DELETE', headers });
+      fetchUsers();
+    } catch (e) {}
+  };
+
+  const startEdit = (u) => {
+    setEditId(u.id);
+    setForm({ username: u.username, password: '', full_name: u.full_name, role: u.role });
+    setShowForm(true);
+    setError('');
+  };
+
+  const roleColors = { ADMIN: '#ef4444', MASTER: '#3b82f6', NAZORATCHI: '#22c55e' };
+
+  return (
+    <div style={{ padding: '1.5rem' }}>
+      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
+        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>Foydalanuvchilar Boshqaruvi</h2>
+        <button onClick={() => { resetForm(); setShowForm(true); }} style={{
+          display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
+          background: 'var(--primary)', color: '#0f172a', border: 'none', borderRadius: '10px',
+          cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem'
+        }}>
+          <Plus size={16} /> Yangi Foydalanuvchi
+        </button>
+      </div>
+
+      {/* Create/Edit Form */}
+      {showForm && (
+        <div style={{
+          background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px',
+          padding: '1.5rem', marginBottom: '1.5rem'
+        }}>
+          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>
+            {editId ? 'Foydalanuvchini Tahrirlash' : 'Yangi Foydalanuvchi'}
+          </h3>
+          {error && <p style={{ color: '#ef4444', fontSize: '0.85rem', margin: '0 0 1rem 0' }}>{error}</p>}
+          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
+            <div>
+              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>Username</label>
+              <input className="input-field" style={{ marginTop: '4px', marginBottom: '0.5rem' }}
+                value={form.username} onChange={e => setForm({...form, username: e.target.value})}
+                disabled={!!editId} placeholder="username" />
+            </div>
+            <div>
+              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>
+                {editId ? 'Yangi Parol (bosh qoldirish)' : 'Parol'}
+              </label>
+              <input className="input-field" type="password" style={{ marginTop: '4px', marginBottom: '0.5rem' }}
+                value={form.password} onChange={e => setForm({...form, password: e.target.value})}
+                placeholder="password" />
+            </div>
+            <div>
+              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>To'liq Ism</label>
+              <input className="input-field" style={{ marginTop: '4px', marginBottom: '0.5rem' }}
+                value={form.full_name} onChange={e => setForm({...form, full_name: e.target.value})}
+                placeholder="Ism Familiya" />
+            </div>
+            <div>
+              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>Rol</label>
+              <select className="input-field" style={{ marginTop: '4px', marginBottom: '0.5rem' }}
+                value={form.role} onChange={e => setForm({...form, role: e.target.value})}>
+                <option value="MASTER">MASTER</option>
+                <option value="NAZORATCHI">NAZORATCHI</option>
+                <option value="ADMIN">ADMIN</option>
+              </select>
+            </div>
+          </div>
+          <div style={{ display: 'flex', gap: '0.5rem', marginTop: '0.5rem' }}>
+            <button onClick={editId ? handleUpdate : handleCreate} style={{
+              display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 20px',
+              background: 'var(--primary)', color: '#0f172a', border: 'none', borderRadius: '10px',
+              cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem'
+            }}>
+              <Save size={14} /> {editId ? 'Saqlash' : 'Yaratish'}
+            </button>
+            <button onClick={resetForm} style={{
