+                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px',
+                padding: '12px', background: `${r.color}15`, color: r.color,
+                border: `1px solid ${r.color}33`, borderRadius: '10px',
+                cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem',
+                transition: 'all 0.2s'
