+import React, { useState, useEffect } from 'react';
+import { Wrench, Clock, CheckCircle, AlertTriangle } from 'lucide-react';
+
+const MechanicPanel = ({ user }) => {
+  const [calls, setCalls] = useState([]);
+  const [filter, setFilter] = useState('ALL');
+
+  const token = localStorage.getItem('token');
+  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
+  const API = `http://${window.location.hostname}:8000`;
+
+  const fetchCalls = async () => {
+    try {
+      const res = await fetch(`${API}/mechanic-calls`, { headers });
+      if (res.ok) setCalls(await res.json());
+    } catch (e) {}
+  };
+
+  useEffect(() => { fetchCalls(); const i = setInterval(fetchCalls, 10000); return () => clearInterval(i); }, []);
+
+  const updateStatus = async (id, status) => {
+    try {
+      await fetch(`${API}/mechanic-calls/${id}`, {
+        method: 'PUT', headers, body: JSON.stringify({ status })
+      });
+      fetchCalls();
+    } catch (e) {}
+  };
+
+  const statusColors = {
+    PENDING: { bg: 'rgba(251,191,36,0.15)', color: '#fbbf24', icon: <Clock size={14} /> },
+    IN_PROGRESS: { bg: 'rgba(59,130,246,0.15)', color: '#3b82f6', icon: <Wrench size={14} /> },
+    RESOLVED: { bg: 'rgba(34,197,94,0.15)', color: '#22c55e', icon: <CheckCircle size={14} /> },
+  };
+
+  const filtered = filter === 'ALL' ? calls : calls.filter(c => c.status === filter);
+
+  return (
+    <div style={{ padding: '1.5rem' }}>
+      <h2 style={{ margin: '0 0 1.5rem 0', fontSize: '1.5rem', fontWeight: 800 }}>
+        <Wrench size={24} style={{ marginRight: '8px', verticalAlign: 'middle' }} />
+        Mexanik Chaqiruvlar
+      </h2>
+
+      <div style={{ display: 'flex', gap: '8px', marginBottom: '1.5rem' }}>
+        {['ALL', 'PENDING', 'IN_PROGRESS', 'RESOLVED'].map(s => (
+          <button key={s} onClick={() => setFilter(s)} style={{
+            padding: '8px 16px', borderRadius: '8px', border: filter === s ? '2px solid var(--primary)' : '1px solid var(--panel-border)',
+            background: filter === s ? 'rgba(0,210,255,0.1)' : 'transparent', color: filter === s ? 'var(--primary)' : 'var(--text-muted)',
+            cursor: 'pointer', fontWeight: 600, fontSize: '0.8rem'
+          }}>
+            {s === 'ALL' ? 'Hammasi' : s === 'PENDING' ? 'Kutilmoqda' : s === 'IN_PROGRESS' ? 'Jarayonda' : 'Hal qilingan'}
+          </button>
+        ))}
+      </div>
+
+      <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
+        {filtered.length === 0 && (
+          <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--text-muted)' }}>
+            <AlertTriangle size={40} style={{ marginBottom: '1rem', opacity: 0.5 }} />
+            <p>Chaqrivlar yo'q</p>
+          </div>
+        )}
+        {filtered.map(call => {
+          const sc = statusColors[call.status] || statusColors.PENDING;
+          return (
+            <div key={call.id} style={{
+              background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '12px',
+              padding: '1rem 1.25rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between'
+            }}>
+              <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
+                <div style={{
+                  width: '40px', height: '40px', borderRadius: '10px', background: sc.bg, color: sc.color,
+                  display: 'flex', alignItems: 'center', justifyContent: 'center'
+                }}>
