+                   ", \"wifi_ssid\":\"" + String(WiFi.SSID()) + "\"" +
+                   ", \"wifi_rssi\":" + String(WiFi.RSSI()) + "}";
+                   
+  Serial.println("USB_DATA:" + payload);
+
+  if (WiFi.status() == WL_CONNECTED || WiFi.softAPgetStationNum() > 0) {
+    HTTPClient http;
+    String url = String(backendUrl) + "S" + String(NODE_ID) + "/update";
