+    
+    if (httpCode <= 0 && WiFi.softAPgetStationNum() > 0) {
+      for (int i = 2; i <= 5; i++) {
+        String apUrl = "http://192.168.4." + String(i) + ":8000/machines/S" + String(NODE_ID) + "/update";
+        http.begin(apUrl);
+        http.addHeader("Content-Type", "application/json");
+        http.setTimeout(500);
+        int res = http.POST(payload);
+        http.end();
+        if (res > 0) break;
+      }
+    }
+  }
+}

